"""Commandes."""

from shutil import which

from .error import CommandNotFound


def is_available(name: str) -> bool:
    """Indique si un exécutable est disponible."""

    return which(name) is not None


def check_available(*args: str) -> None:
    """Vérifie la disponibilités des exécutables.

    Chaque exécutable est recherché dans l'ordre spécifié. Dès qu'un exécutable
    n'est pas trouvé, une exception CommandNotFound est levée.
    """
    for name in args:
        if not is_available(name):
            raise CommandNotFound(name)
